        assert_eq!(est.estimate("hi"), 1);
    }
fn test_typical_text() {
        let est = CharDivFourEstimator;
        let text = "The quick brown fox jumps over the lazy dog.";
        assert_eq!(est.estimate(text), 11);
    }
